import { useContext, useState } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { AuthContext } from '../../context/';

import Navbar from '../UI/navbar/Navbar';

const Login = () => {
  const { setIsAuth, setUser } = useContext(AuthContext);
  const [username, setUsername] = useState('');
  const [role, setRole] = useState('1'); // 1 = user, 3 = admin
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    const userData = { nome: username, categoria: role };

    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
    setIsAuth(true);

    navigate('/');
  };

  return (
    <div className="container">
      <Navbar />
      <div className="main-content">
        <div className="content">
          <h3>Страница для логина</h3>
          <div className="article-list">
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <form className="forma-login" onSubmit={handleSubmit(onSubmit)}>
        <div>
          <input
            type="text"
            placeholder="Username"
            {...register('username', { required: 'Username obbligatorio' })}
          />
          {errors.username && <p>{errors.username.message}</p>}
        </div>
        <div>
          <input
            type="password"
            placeholder="Password"
            {...register('password', { required: 'Password obbligatoria' })}
          />
          {errors.password && <p>{errors.password.message}</p>}
        </div>
        <button type="submit">Login</button>
      </form>
      </div>
      </div>
      </div>
    </div>
  );
};

export default Login;
